scwin.onpageload = function () {
    const codeOptions = [
        { grpCd: "FM036", compID: "gr_collMoneyList:acctRecvStsCd,acb_acctRecvStsCd", opt : {'range': '2,1'} },
        { grpCd: "SD020", compID: "gr_collMoneyList:stmtPrdClsCd" },
        { grpCd: "SD010", compID: "gr_collMoneyList:collMoneyCntShtCd" },
    ];

    $c.data.setCommonCode(codeOptions);

};

scwin.onUdcCompleted = function() {
    scwin.f_setCompanyInfo();
	ed_FromDate.setValue(scwin.strFromDate);
	ed_ToDate.setValue(scwin.strToDate);
	ica_cancelDt.setValue(scwin.strToDate); 

    dma_addCollMoney.insertRow(0);
    dma_searchCollMoney.set("queryDeptSearchStDate", scwin.strFromDate) // dma -> ds ліҖкІҪлҗ мҲҳмһҲмқҢ.
    dma_addCollMoney.setCellData(0, "queryDeptSearchStDate", scwin.strFromDate) // dma -> ds ліҖкІҪлҗ мҲҳмһҲмқҢ.
    dma_searchCollMoney.set("queryDeptSearchEndDate", scwin.strToDate) // dma -> ds ліҖкІҪлҗ мҲҳмһҲмқҢ.
    dma_addCollMoney.setCellData(0, "queryDeptSearchEndDate", scwin.strToDate) // dma -> ds ліҖкІҪлҗ мҲҳмһҲмқҢ.
    dma_addCollMoney.modifyRowStatus(0, "R")
    $c.sbm.execute(sbm_admin);
};


