scwin.f_Retrieve = async function () { 
    if(! await $c.gus.cfValidate([ed_coCd])) 
        return ;  

    dma_searchCollMoney.set("queryDeptSearchStDate", ed_FromDate.getValue()) // dma -> ds ліҖкІҪлҗ мҲҳмһҲмқҢ.
    dma_addCollMoney.setCellData(0, "queryDeptSearchStDate", ed_FromDate.getValue()) // dma -> ds ліҖкІҪлҗ мҲҳмһҲмқҢ.
    dma_searchCollMoney.set("queryDeptSearchEndDate", ed_ToDate.getValue()) // dma -> ds ліҖкІҪлҗ мҲҳмһҲмқҢ.
    dma_addCollMoney.setCellData(0, "queryDeptSearchStDate", ed_FromDate.getValue()) // dma -> ds ліҖкІҪлҗ мҲҳмһҲмқҢ.

    if (ed_FromDate.getValue() > ed_ToDate.getValue()) {
        await $c.win.alert("мЎ°нҡҢ мӢңмһ‘мқјмһҗлҠ” л§Ңкё°мқјмһҗліҙлӢӨ мқҙм „ лӮ м§ң мқҙм–ҙм•ј н•©лӢҲлӢӨ.");
        ed_FromDate.focus();
        return;
    }

    // н•„мҲҳмһ…л ҘмӮ¬н•ӯ мІҙнҒ¬
    if (! await $c.gus.cfValidate([ed_FromDate,ed_ToDate,ed_acctDeptCd]) ) {
        return;
    }

    $c.sbm.execute(sbm_searchCollMoney);
}

