scwin.f_openPopUp = async function(select_code) {
    if(select_code == '1' ||  select_code == '3'){ 
        if(! await $c.gus.cfValidate([ed_coCd]))
        return;``
    }
    let code = ""
    let param = ""
    switch (select_code) {
        // кҙҖлҰ¬л¶Җм„ң PopUp нҳём¶ң
        case '1' :
            // ed_acctDeptNm.setValue("");
            code = ed_acctDeptCd.getValue();
            param = ed_FromDate.getValue().trim()+","+ ed_coCd.getValue()+","+scwin.txtCoClsCd+",,,"; //мһҗнҡҢмӮ¬ нҡҢкі„мӢңмҠӨн…ң м¶”к°ҖмӮ¬н•ӯ 
            udc_dept.cfCommonPopUp(scwin.udc_dept_callBackFunc,code,'',"T",null,null,null,null,param,null,null,null,null); // мІӯкө¬к·ҖмҶҚл¶Җм„ң

            // if ( rtnList != null ) {
            //     if ( rtnList[0] == "N/A" ) return ;
            //     ed_acctDeptCd.setValue(rtnList[0]);	// кҙҖлҰ¬л¶Җм„ңмҪ”л“ң
            //     ed_acctDeptNm.setValue(rtnList[1]);	// кҙҖлҰ¬л¶Җм„ңлӘ…
            //     ed_acctDeptCd.hidVal = rtnList[0];
            // }
            // else {
            //     ed_acctDeptCd.setValue("");
            // }
            break;
        // л“ұлЎқмһҗ POPUP нҳём¶ң
        case '2' :
            // ed_mgntEmpNm.setValue("");
            code = ed_mgntEmpNo.getValue();
            udc_empinfo.cfCommonPopUp(scwin.udc_empinfo_callBackFunc,code,'',"T",null,null,null,null,null,null,null,null,null); // мӮ¬мӣҗ

            // if ( rtnList != null ) {
            //     if ( rtnList[0] == "N/A" ) return ;
            //     ed_mgntEmpNo.setValue(rtnList[0]); // мӮ¬мӣҗлІҲнҳё
            //     ed_mgntEmpNm.setValue(rtnList[1]); // мӮ¬мӣҗлӘ…
            //     ed_mgntEmpNo.hidVal = rtnList[0]; // Hidden мӮ¬мӣҗлІҲнҳё
            // } else {
            //     ed_mgntEmpNo.setValue("");
            // }
            break;
        // мЎ°нҡҢмЎ°кұҙмҡ© кұ°лһҳмІҳ PopUp нҳём¶ң
            case '3' :   
            code = ed_sclntNo.getValue();
            param  = ""+ed_coCd.getValue();	//мһҗнҡҢмӮ¬ нҡҢкі„мӢңмҠӨн…ң м¶”к°ҖмӮ¬н•ӯ
            udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc,code,'',"T",null,null,null,null,param,null,null,null,null); // кұ°лһҳмІҳ(лӘЁл“  кұ°лһҳмІҳлҘј лӢӨ мЎ°нҡҢн•ңлӢӨ.)
            // if ( rtnList != null ) {
            //     if ( rtnList[0] == "N/A" ) return ;
            //     ed_sclntNo.setValue(rtnList[0]); // кұ°лһҳмІҳмҪ”л“ң
            //     ed_sclntNm.setValue(rtnList[1]); // кұ°лһҳмІҳлӘ…
            //     ed_sclntNo.hidVal = rtnList[0]; // Hidden кұ°лһҳмІҳмҪ”л“ң
            // } else {
            //     ed_sclntNo.setValue("");
            // }
            break;
            case '6':
                // мҲҳкёҲмҡ”мІӯ мҠ№мқёмһҗ м§Җм • 
                code = ed_apprvEmpNo.getValue();
                param =",,," ; //мһҗнҡҢмӮ¬ нҡҢкі„мӢңмҠӨн…ң м¶”к°ҖмӮ¬н•ӯ
                udc_apprvEmpNo.cfCommonPopUp(scwin.udc_apprvEmpNo_callBackFunc,code,"","F",null,null,null,null,param ,"450","500",null,null); 			
                // л„ҳм–ҙмҳЁ OBJк°Җ EMEditмқём§Җ TextBoxмқём§Җ кө¬л¶„н•ңлӢӨ.
                // if (rtnList != null ) {
                //     if ( rtnList[0] == "N/A" ) return ;

                //     ed_apprvEmpNo.setValue(rtnList[0]);	// мҠ№мқёмһҗмӮ¬лІҲ
                //     ed_apprvEmpNm.setValue(rtnList[1]);	// мҠ№мқёмһҗлӘ…

                // } else {
                //     ed_apprvEmpNo.setValue("");	// мҠ№мқёмһҗмӮ¬лІҲ
                //     ed_apprvEmpNm.setValue("");	// мҠ№мқёмһҗлӘ…
                // }
                break;	 	

        default :
            await $c.win.alert("мһҳлӘ»лҗң Functionнҳём¶ң мһ…лӢҲлӢӨ. кҙҖлҰ¬мһҗм—җкІҢ л¬ёмқҳн•ҳмӢңкё° л°”лһҚлӢҲлӢӨ.");
            break;
    } 
}

