//-------------------------------------------------------------------------
// мҲҳкёҲм·ЁмҶҢ н•ЁмҲҳ нҳём¶ң
//-------------------------------------------------------------------------
scwin.f_ApprvCancel = async function () { 
    // н•„мҲҳ мһ…л Ҙ м—¬л¶Җ Check(л¶Җм„ң лӮ м§ң кІҖмғүмӢң мқҙмҡ©лҗЁ)
    if (! await $c.gus.cfValidate([ed_FromDate,ed_ToDate])) {
        return;
    }   

    // н•„мҲҳмһ…л ҘмӮ¬н•ӯ мІҙнҒ¬
    if (! await $c.gus.cfValidate([ica_cancelDt,ed_acctDeptCd]) ) {
        return;
    }

    if (!ds_collMoneyList.getModifiedIndex().length > 0) {
        await $c.win.alert("м„ нғқн•ҳмӢ  мӮ¬н•ӯмқҙ м—ҶмҠөлӢҲлӢӨ.");
        return;
    }

    let admin = "";
    let sChkUser = 0;
    let empNo = scwin.login.empNo;

    // ds_admin.SyncLoad = true;
    // ds_admin.DataID = "/cm.zz.RetrieveCodeCMD.do?grpCd=FM096&cd=&cdNm=";
    // ds_admin.Reset();

    for(let i=0; i< ds_admin.getRowCount(); i++){
        admin = ds_admin.getCellData(i, "cd");

        if(empNo == admin){
            sChkUser++;
        }
    }

    for (i = 0; i < ds_collMoneyList.getRowCount(); i++) {
        if (ds_collMoneyList.getCellData(i, "num") == "T") {

            if ( sChkUser == '0' ) {
                if(empNo !="021169"){ //мЎ°м •мҡұ кіјмһҘ к¶Ңн•ң 

                    //лЎңк·ёмқён•ң мӮ¬лһҢмқҳ мӮ¬лІҲкіј мҲҳкёҲмӮ¬н•ӯмқ„ мһ‘м„ұмһҗмқҳ мӮ¬лІҲмқҙ к°ҷм§Җ м•Ҡмңјл©ҙ...
                    if ( empNo != ds_collMoneyList.getCellData(i, "drawEmpNo").trim()){
                        await $c.win.alert(i+1+"н–үмқҳ мҲҳкёҲмӮ¬н•ӯмһ‘м„ұмһҗлҠ” "+ds_collMoneyList.getCellData(i, "drawEmpNm")+" мқҙм–ҙм„ң м·ЁмҶҢн•  мҲҳ м—ҶмҠөлӢҲлӢӨ");			
                        return;
                    } 
                }

                //мҲҳкёҲм·ЁмҶҢмқјмһҗмҷҖ мҲҳкёҲн•ңмқјмһҗмқҳ л…„мӣ”мқҙ лӢӨлҘҙл©ҙ...
                if ( ica_cancelDt.getValue().substring(0,6) != ds_collMoneyList.getCellData(i, "wrkDt").substring(0,6)){
                    await $c.win.alert(i+1+"н–үмқҳ мһ‘м„ұл…„мӣ”мқҙ мғҒмқҙн•ҳм—¬ мҲҳкёҲм·ЁмҶҢн•  мҲҳ м—ҶмҠөлӢҲлӢӨ.");			
                    return;
                }

                //мҲҳкёҲмғҒнғңк°Җ мҲҳкёҲм·ЁмҶҢмҡ”мІӯмқҙ м•„лӢҢкІҪмҡ°.
                if (ds_collMoneyList.getCellData(i, "acctRecvStsCd")!="16") {
                    await $c.win.alert(i+1+"н–үмқҳ м„ нғқмӮ¬н•ӯмқҖ мғҒнғңк°Җ м·ЁмҶҢмҡ”мІӯмқҙ м•„лӢҷлӢҲлӢӨ.\nмғҒнғңк°Җ м·ЁмҶҢмҡ”мІӯмқёкІғл§Ң мҠ№мқё к°ҖлҠҘн•©лӢҲлӢӨ.");
                    ds_collMoneyList.setRowPosition(i);
                    return;
                } 
            }

            //м·ЁмҶҢм „н‘ңлІҲнҳёк°Җ мһҲмңјл©ҙ...
            if (ds_collMoneyList.getCellData(i, "cnclSlipNo") != "") {
                await $c.win.alert(i+1+"н–үмқҳ мҲҳкёҲмӮ¬н•ӯмқҖ мҲҳкёҲм·ЁмҶҢ н•ҳмӢӨмҲҳ м—ҶлҠ” мғҒнғң мһ…лӢҲлӢӨ.");
                ds_collMoneyList.setRowPosition(i);
                return;
            }

            //мҲҳкёҲмқҳ delYnмқҳ мғҒнғңк°Җ мӮӯм ңмқёкІҪмҡ°.
            if (ds_collMoneyList.getCellData(i, "delYn") == "1") {
                await $c.win.alert(i+1+"н–үмқҳ мҲҳкёҲмӮ¬н•ӯмқҖ мқҙлҜё мӮӯм ңмІҳлҰ¬лҗҳм—ҲмҠөлӢҲлӢӨ. нҷ•мқён•ҳмӢңкё° л°”лһҚлӢҲлӢӨ.");
                ds_collMoneyList.setRowPosition(i);
                return;
            }

            if(scwin.vLoginCoCd=="000"||scwin.vLoginCoCd=="029"){
                //мҲҳкёҲмғҒнғңк°Җ мҲҳкёҲлҳҗлҠ” мҲҳкёҲм·ЁмҶҢмҡ”мІӯмқҙ м•„лӢҢкІҪмҡ°.
                if (ds_collMoneyList.getCellData(i, "acctRecvStsCd")==ACConstants.COLLECION_OF_MONEY_COLLOFMONEY||
                    ds_collMoneyList.getCellData(i, "acctRecvStsCd")=="16") {

                }else{
                    await $c.win.alert(i+1+"н–үмқҳ м„ нғқмӮ¬н•ӯмқҖ мғҒнғңк°Җ мҲҳкёҲмҡ”мІӯмқҙ м•„лӢҷлӢҲлӢӨ.\nмғҒнғңк°Җ  мҲҳкёҲмҡ”мІӯ мқёкІғл§Ң мҲҳкёҲм·ЁмҶҢмҠ№мқё к°ҖлҠҘн•©лӢҲлӢӨ.");
                    ds_collMoneyList.setRowPosition(i);
                    return;
                }
            }else{
                //мҲҳкёҲмғҒнғңк°Җ мҲҳкёҲлҳҗлҠ” мҲҳкёҲм·ЁмҶҢмҡ”мІӯмқҙ м•„лӢҢкІҪмҡ°.
                if (ds_collMoneyList.getCellData(i, "acctRecvStsCd")==ACConstants.COLLECION_OF_MONEY_COLLOFMONEY) {

                }else{
                    await $c.win.alert(i+1+"н–үмқҳ м„ нғқмӮ¬н•ӯмқҖ мғҒнғңк°Җ мҲҳкёҲмқҙ м•„лӢҷлӢҲлӢӨ.\nмғҒнғңк°Җ мҲҳкёҲ мқёкІғл§Ң мҲҳкёҲм·ЁмҶҢк°Җ к°ҖлҠҘн•©лӢҲлӢӨ.");
                    ds_collMoneyList.setRowPosition(i);
                    return;
                }
            }
        }
    }

    if (await $c.win.confirm("м„ нғқн•ҳмӢ  мӮ¬н•ӯмқ„ мҲҳкёҲм·ЁмҶҢ н•ҳмӢңкІ мҠөлӢҲк№Ң")) {
        for (i = 0; i < ds_collMoneyList.getRowCount(); i++) {
            if (ds_collMoneyList.getCellData(i, "num") == "T") {
                // м·ЁмҶҢмқјмһҗлҘј к°Ғ Rowм—җ мһ…л Ҙн•ңлӢӨ.
                ds_collMoneyList.setCellData(i, "cnclDt", ica_cancelDt.getValue());
            }
        }

        // let sSlipNo = "";

        sbm_saveCollMoney.action = "/ac.fm.collmoneymgnt.collmoneymgnt.CancelCollectionOfMoneyCMD.do";
        $c.sbm.execute(sbm_saveCollMoney);
    }
}


