scwin.f_CancelDelete = async function () {
    // н•„мҲҳ мһ…л Ҙ м—¬л¶Җ Check(л¶Җм„ң лӮ м§ң кІҖмғүмӢң мқҙмҡ©лҗЁ)
    if (! await $c.gus.cfValidate([ed_FromDate,ed_ToDate])) {
        return;
    }   
    // н•„мҲҳмһ…л ҘмӮ¬н•ӯ мІҙнҒ¬
    if (! await $c.gus.cfValidate([ica_cancelDt,ed_mgntEmpNo,ed_acctDeptCd]) ) {
        return;
    }

    if (!ds_collMoneyList.getModifiedIndex().length > 0) {
        await $c.win.alert("м„ нғқн•ҳмӢ  мӮ¬н•ӯмқҙ м—ҶмҠөлӢҲлӢӨ.");
        return;
    }

    for (i = 0; i < ds_collMoneyList.getRowCount(); i++) {
        if (ds_collMoneyList.getCellData(i, "num") == "T") {
            if (ds_collMoneyList.getCellData(i, "cnclSlipNo") == "" && ds_collMoneyList.getCellData(i, "delYn") == "0" ) {
                await $c.win.alert(i+1+"н–үмқҳ мҲҳкёҲмӮ¬н•ӯмқҖ мҲҳкёҲм·ЁмҶҢмӮӯм ң н•ҳмӢӨмҲҳ м—ҶлҠ” мғҒнғңмһ…лӢҲлӢӨ.");
                return;
            }
            if (ds_collMoneyList.getCellData(i, "cnclDt") === "") {
                await $c.win.alert(i+1+"н–үмқҳ мҲҳкёҲмӮ¬н•ӯмқҖ мҲҳкёҲм·ЁмҶҢмӮӯм ң н•ҳмӢӨмҲҳ м—ҶлҠ” мғҒнғңмһ…лӢҲлӢӨ.");
                return;
            }
            if (ds_collMoneyList.getCellData(i, "acctRecvStsCd")!=ACConstants.COLLECION_OF_MONEY_COLLOFMONEY) {
                await $c.win.alert(i+1+"н–үмқҳ м„ нғқмӮ¬н•ӯмқҖ мғҒнғңк°Җ мҲҳкёҲмқҙ м•„лӢҷлӢҲлӢӨ.\nмғҒнғңк°Җ мҲҳкёҲ мқёкІғл§Ң мҲҳкёҲм·ЁмҶҢмӮӯм ңк°Җ к°ҖлҠҘн•©лӢҲлӢӨ.");
                ds_collMoneyList.setRowPosition(i);
                return;
            }
        }
    }

    if (await $c.win.confirm("м„ нғқн•ҳмӢ  мӮ¬н•ӯмқ„ мҲҳкёҲм·ЁмҶҢмӮӯм ң н•ҳмӢңкІ мҠөлӢҲк№Ң")) {
        for (i = 0; i < ds_collMoneyList.getRowCount(); i++) {
            if (ds_collMoneyList.getCellData(i, "num") == "T") {
                // м·ЁмҶҢмқјмһҗлҘј к°Ғ Rowм—җ мһ…л Ҙн•ңлӢӨ.
                ds_collMoneyList.setCellData(i, "cancelDt", ica_cancelDt.getValue());
            }
        }

        sbm_saveCollMoney.action = "/ac.fm.collmoneymgnt.collmoneymgnt.DeleteCollectionOfMoneyCancelCMD.do";
        $c.sbm.execute(sbm_saveCollMoney);
        // л“ұлЎқ нҷ”л©ҙм—җ лҢҖн•ң мһ¬мЎ°нҡҢ (мһҗлҸҷмЎ°нҡҢ мЈјм„қмІҳлҰ¬ 2006.03.16)
    //	  	if (parent.iFrame0.ed_sclntNo.getValue() != "" && parent.iFrame0.ed_sacctDeptCd.getValue() != "" ) {
    //		  	parent.iFrame0.$c.sbm.execute(sbm_searchAcctRecv);
            //scwin.f_Retrieve();
    //		}
    }

}



