scwin.f_Apprv = async function () { 
    if (!ds_collMoneyList.getModifiedIndex().length > 0) {
        await $c.win.alert("м„ нғқн•ҳмӢ  мӮ¬н•ӯмқҙ м—ҶмҠөлӢҲлӢӨ.");
        return;
    }

    let empNo = scwin.login.empNo;

    for (i = 0; i < ds_collMoneyList.getRowCount(); i++) {
        if (ds_collMoneyList.getCellData(i, "num") == "T") {

            if(empNo != "021169"){ //мЎ°м •мҡұ кіјмһҘ к¶Ңн•ң
                //лЎңк·ёмқён•ң мӮ¬лһҢмқҳ мӮ¬лІҲкіј мҠ№мқёмһҗмқҳ мӮ¬лІҲмқҙ к°ҷм§Җ м•Ҡмңјл©ҙ...
                if ( empNo != ds_collMoneyList.getCellData(i, "apprvEmpNo").trim()){
                    await $c.win.alert(i+1+"н–үмқҳ мҠ№мқёмһҗлҠ” "+ds_collMoneyList.getCellData(i, "apprvEmpNm")+" мқҙм–ҙм„ң мҠ№мқён•  мҲҳ м—ҶмҠөлӢҲлӢӨ");			
                    return;
                } 
            }

            //мҲҳкёҲмғҒнғңк°Җ мҲҳкёҲмҡ”мІӯмқҙ м•„лӢҢкІҪмҡ°.
            if (ds_collMoneyList.getCellData(i, "acctRecvStsCd")!="15") {
                await $c.win.alert(i+1+"н–үмқҳ м„ нғқмӮ¬н•ӯмқҖ мғҒнғңк°Җ мҲҳкёҲмҡ”мІӯмқҙ м•„лӢҷлӢҲлӢӨ.\nмғҒнғңк°Җ мҲҳкёҲмҡ”мІӯмқёкІғл§Ң мҠ№мқё к°ҖлҠҘн•©лӢҲлӢӨ.");
                ds_collMoneyList.setRowPosition(i)
                return;
            }

            if(scwin.vLoginCoCd=="000"||scwin.vLoginCoCd=="029"){
                let wrkDt = ds_collMoneyList.getCellData(i, "wrkDt")
                // л§Ҳк°җмқҙнӣ„мқҳ мҲҳкёҲм·ЁмҶҢ к¶Ңн•ң
                if(empNo !="021169"){ //мЎ°м •мҡұ кіјмһҘ к¶Ңн•ң
                    // л§Ҳк°җм—¬л¶Җ нҷ•мқё
                    if ( ! await scwin.f_JobCloseYN(wrkDt) ) {
                        return;
                    }
                }
            }
        }
    }

    if (await $c.win.confirm("м„ нғқн•ҳмӢ  мӮ¬н•ӯмқ„ мҠ№мқё н•ҳмӢңкІ мҠөлӢҲк№Ң")) {
        sbm_apprvCollMoney.action = "/ac.fm.collmoneymgnt.collmoneymgnt.ApprvCollOfMoneyCMD.do";
        $c.sbm.execute(sbm_apprvCollMoney);
    }
}    

//-------------------------------------------------------------------------
// л§Ҳк°җмІҙнҒ¬
//-------------------------------------------------------------------------
scwin.f_JobCloseYN = async function(wrkDt){
    let wrkNo = ACConstants.CLOSE_MONTH;
    //cfJobCloseYN(л§Ҳк°җмҡ”мІӯкө¬л¶„,л§Ҳк°җл…„мӣ”,л§Ҳк°җмқј,мһ‘м—…лІҲнҳё,кҙҖлҰ¬лІҲнҳё,лҰ¬н„ҙкө¬л¶„);
    let isClose = await udc_closeYn.cfJobCloseYN(
                                                "CUR",
                                                wrkDt.substring(0,6),
                                                "00",
                                                wrkNo,
                                                "0",
                                                "ARR",
                                                "N",
                                                ed_coCd.getValue());

    // л§Ҳк°җмһ‘м—… мЎ°нҡҢмӢң н•ҙлӢ№к°’мқҙ м—Ҷмқ„кІҪмҡ° мҳӨлҘҳ л°ңмғқ
    if ( isClose[0] == "DNF" ) {
        await $c.win.alert("л§Ҳк°җлҗҳм—ҲмҠөлӢҲлӢӨ.");
        return false;
    }

    // м„ н–үл§Ҳк°җ мһ‘м—…м—җ лҢҖн•ң кІҖмӮ¬
    if ( isClose[3] == "PRE" ) {
        if (isClose[0]=="1") {
            await $c.win.alert("м„ н–үмһ‘м—… "+isClose[2]+"мқҙ лҜёл§Ҳк°җлҗҳм–ҙм„ң нҳ„мһ¬ мһ‘м—…мқ„ м§„н–үн•  мҲҳ м—ҶмҠөлӢҲлӢӨ.");
            return false;
        } else if (isClose[0]=="0") {
            await $c.win.alert("м„ н–үмһ‘м—… "+isClose[2]+"мқҙ л§Ҳк°җмһ‘м—…мӨ‘мқҙм–ҙм„ң нҳ„мһ¬ мһ‘м—…мқ„ м§„н–үн•  мҲҳ м—ҶмҠөлӢҲлӢӨ.");
            return false;
        } 
    } 

    // н•ҙлӢ№л§Ҳк°җ мһ‘м—…м—җ лҢҖн•ң кІҖмӮ¬
    if ( isClose[3] == "CUR" ) {
        if(isClose[0]=="0"){await $c.win.alert(isClose[2] + "(мқҙ)к°Җ л§Ҳк°җмӨ‘мһ…лӢҲлӢӨ.");
            return false;
            }else if(isClose[0]=="2"){await $c.win.alert(isClose[2] + "(мқҙ)к°Җ л§Ҳк°җмҷ„лЈҢк°Җ лҗҳм—ҲмҠөлӢҲлӢӨ");
            return false;
        }else {
            return true;
        }
    }
}




